def classify(text):
    text = text.lower()
    scores = {cat: 0 for cat in categories}

    # Special handling for "game"
    if 'game' in text:
        # Check if it looks like video games
        if any(x in text for x in ['video', 'console', 'nintendo', 'sony', 'xbox', 'playstation', 'wii', 'psp', 'ds', 'gamer', 'software', 'computer', 'app']):
            scores['Science/Technology'] += 2
        # Check if it looks like sports
        elif any(x in text for x in ['league', 'season', 'coach', 'team', 'score', 'player', 'football', 'soccer', 'basketball', 'baseball', 'sport']):
            scores['Sports'] += 2
        else:
            # Ambiguous, give slight weight to both or ignore
            pass

    for cat, keywords in categories.items():
        for kw in keywords:
            if kw in text:
                scores[cat] += 1

    # Tie-breaking logic or max
    # If Science/Technology and Business have equal score, check content.
    # Usually tech products (iPod, Windows) are Tech. Company earnings are Business.
    # If "profit", "stock", "revenue" in text -> Business strong.
    if scores['Business'] > 0 and scores['Business'] == scores['Science/Technology']:
        if any(x in text for x in ['profit', 'stock', 'market', 'price', 'revenue', 'earnings']):
            scores['Business'] += 0.5
        else:
            scores['Science/Technology'] += 0.5 # Default to Tech if it's about a tech company product launch

    # If World and Business match (e.g. oil prices in a country)
    if scores['World'] > 0 and scores['World'] == scores['Business']:
        if any(x in text for x in ['oil', 'price', 'trade', 'economy']):
            scores['Business'] += 0.5
        else:
            scores['World'] += 0.5

    best_cat = max(scores, key=scores.get)
    if scores[best_cat] == 0:
        return 'Unknown'
    return best_cat

count_tech = 0
total = len(articles)
tech_articles = []

for article in articles:
    content = article['title'] + " " + article['description']
    category = classify(content)
    if category == 'Science/Technology':
        count_tech += 1
        tech_articles.append(article['title'])

fraction = count_tech / total if total > 0 else 0

print("__RESULT__:")
print(json.dumps({
    "total": total,
    "tech_count": count_tech,
    "fraction": fraction,
    "tech_titles": tech_articles
}))
"}

